#include <bits/stdc++.h>
using namespace std;
const int N=400005;
int n,m,ans[N],num[N][25];
struct node
{
	int id,l,r;
	bool operator<(const node other) const
	{
		return l<other.l;
	}
} a[N];
int main()
{
	cin>>n>>m;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i].l>>a[i].r;
		if(a[i].r<a[i].l) a[i].r+=m;
		a[i].id=i;
	}
	sort(a+1,a+1+n);
	for(int i=1;i<=n;i++)
	{
		a[i+n]=node{a[i].id,a[i].l+m,a[i].r+m};
	}
	for(int l=1,r=1;l<=2*n;l++) 
	{
		while((r<=2*n)&&a[r].l<=a[l].r) r++;
//		cout<<r<<"  aa  ";
		// 上面这行代码 不用考虑 a[i].l>a[i-1].l 且 a[i].r<a[i-1].r 的情况  (因为不存在  题目中说“N 名边防战士都是精心挑选的，身体素质极佳，所以每名边防战士的奔袭区间都不会被其他边防战士的奔袭区间所包含。”  上一个AC的注释写错了)
		num[l][0]=r-1;
	}
//	cout<<"\n";
	for(int i=1;i<=log2(n);i++)
	{
		for(int j=1;j<=2*n;j++)
		{
			num[j][i]=num[num[j][i-1]][i-1];
//			cout<<num[j][i]<<" ";
		}
//		cout<<"\n";
	}
	for(int i=1;i<=n;i++)
	{
		int tmp=a[i].l+m,ans2=1;
		for(int j=log2(n),l=i;j>=0;j--)
		{
			if(num[l][j]!=0&&a[num[l][j]].r<tmp)
			{
				ans2+=(1<<j);
				l=num[l][j];
			}
		}
		ans[a[i].id]=ans2+1;
	}
	for(int i=1;i<=n;i++) cout<<ans[i]<<" ";
	return 0;
}
